import{codes}from"micromark-util-symbol";export const asciiAlpha=regexCheck(/[A-Za-z]/);export const asciiAlphanumeric=regexCheck(/[\dA-Za-z]/);export const asciiAtext=regexCheck(/[#-'*+\--9=?A-Z^-~]/);export function asciiControl(e){return null!==e&&(e<codes.space||e===codes.del)}export const asciiDigit=regexCheck(/\d/);export const asciiHexDigit=regexCheck(/[\dA-Fa-f]/);export const asciiPunctuation=regexCheck(/[!-/:-@[-`{-~]/);export function markdownLineEnding(e){return null!==e&&e<codes.horizontalTab}export function markdownLineEndingOrSpace(e){return null!==e&&(e<codes.nul||e===codes.space)}export function markdownSpace(e){return e===codes.horizontalTab||e===codes.virtualSpace||e===codes.space}export const unicodePunctuation=regexCheck(/\p{P}|\p{S}/u);export const unicodeWhitespace=regexCheck(/\s/);function regexCheck(e){return function(o){return null!==o&&o>-1&&e.test(String.fromCharCode(o))}}